ALTER TABLE "evidence" ADD CONSTRAINT "evidence_tool_invocation_reconciliation_shape" CHECK ("evidence"."type" <> 'tool_invocation_reconciliation' OR ("evidence"."authority" = 'application' AND "evidence"."application_rule_id" = 'tool_invocation.abandoned_write' AND "evidence"."application_rule_version" = 1 AND "evidence"."payload" ->> 'source' = 'tool_invocation_ledger' AND "evidence"."payload" ->> 'observer' = 'application_code' AND "evidence"."payload" ->> 'durableObservation' = 'expired_claim_without_terminal_result' AND "evidence"."payload" ->> 'reconciledOutcome' = 'still_unknown' AND "evidence"."payload" -> 'observedResultHash' = 'null'::jsonb AND "evidence"."payload" -> 'observedAttemptId' = 'null'::jsonb AND "evidence"."payload" ->> 'toolCallId' ~ '^call_[a-z0-9][a-z0-9_-]{7,63}$' AND "evidence"."payload" ->> 'toolName' IN ('palaces.get', 'crews.list', 'capabilities.list', 'routines.list', 'routines.get', 'executions.list', 'knowledge.search', 'plans.propose', 'plans.validate', 'plans.simulate', 'plans.request_approval', 'plans.activate', 'operations.get', 'verification.get_evidence', 'missions.cancel') AND "evidence"."payload" ->> 'invocationBindingHash' ~ '^[a-f0-9]{64}$' AND "evidence"."payload" ->> 'observationHash' ~ '^[a-f0-9]{64}$' AND ("evidence"."payload" ->> 'abandonedClaimGeneration')::integer > 0 AND ("evidence"."payload" ->> 'claimExpiredAt')::timestamptz <= "evidence"."observed_at"));